            // Weight(root_v -> root_u) = Weight(P_v) + w + Weight(P_u)

            int new_parity_rv_to_ru = (parity_v_to_root_v + w + parity_u_to_root_u) % 2;

            parity[root_v] = new_parity_rv_to_ru;
            return true;
        } else {
            // The nodes are already in the same component. Adding the edge (u, v) of weight w
            // creates a cycle. We must check the parity of this cycle.

            // Cycle path: u --(path P_u)--> root_u --(path P_v)--> v --(edge w)--> u
            // Total cycle weight = Weight(u -> root_u) + Weight(root_u -> v) + w
            // Since root_u == root_v, Weight(root_u -> v) = Weight(v -> root_u) = parity_v_to_root_v
            // Cycle Weight (mod 2) = parity_u_to_root_u + parity_v_to_root_v + w (mod 2)

            int cycle_parity = (parity_u_to_root_u + parity_v_to_root_v + w) % 2;

            // We only add the edge if the cycle weight is EVEN (0 mod 2).
            return cycle_parity == 0;
        }
    }
};


long long solve(long long n, std::vector<std::vector<long long>> edges) {
    // DSU structure handles the connectivity and parity information simultaneously.
    DSU dsu(n);
    int added_edges_count = 0;

    for (const auto& edge : edges) {
        int u = (int)edge[0];
        int v = (int)edge[1];
        int w = (int)edge[2];

        // Try to unite/add the edge. unite returns true if it's added successfully
        // (either forming a new component or closing an even cycle).
        if (dsu.unite(u, v, w)) {
            added_edges_count++;
        }
    }

    return added_edges_count;
}
